def min_unvisited(dist: list[int], used: list[bool]) -> int {
    best_index: int = -1;
    best_value: int = 999999;
    i: int = 0;
    while i < len(dist) {
        if !used[i] {
            if dist[i] < best_value {
                best_value = dist[i];
                best_index = i;
            }
        }
        i = i + 1;
    }
    return best_index;
}

def shortest_from_zero(costs: list[list[int]]) -> list[int] {
    n: int = len(costs);
    dist: list[int] = [999999, 999999, 999999, 999999];
    used: list[bool] = [false, false, false, false];
    dist[0] = 0;

    step: int = 0;
    while step < n {
        u: int = min_unvisited(dist, used);
        if u == -1 {
            break;
        }
        used[u] = true;
        v: int = 0;
        while v < n {
            cost: int = costs[u][v];
            if cost > 0 {
                alt: int = dist[u] + cost;
                if alt < dist[v] {
                    dist[v] = alt;
                }
            }
            v = v + 1;
        }
        step = step + 1;
    }
    return dist;
}

